typedef enum bit[10:0] { stateReset, delayAfterReset, sendQPIWriteCmd } StateMachine;
StateMachine state, next;
int i;
always_ff @(posedge clk) begin
  if (i < 5) i++;
  state <= next;
end
always_comb begin
  if (i == 5) $display("i is 5");
  case (state)
    stateReset: next = delayAfterReset;
    delayAfterReset: next = sendQPIWriteCmd;
  endcase
end

typedef enum bit[10:0] { stateReset, delayAfterReset, sendQPIWriteCmd } StateMachine;
StateMachine state, next;
always_ff @(posedge clk) state <= next;
always_comb begin
  case (state)
    stateReset: next = delayAfterReset;
    delayAfterReset: next = sendQPIWriteCmd;
  endcase
end

int i;
logic [10:0] state, next;
always_ff @(posedge clk) begin
  if (i < 5) i++;
  state <= next;
end
always_comb begin
  if (i == 5) $display("done");
  next = state + 1;
end
